import React, { useState } from 'react';
import { Box, TextField, Button, Typography, FormControl, InputLabel, Select, MenuItem, Grid, Paper } from '@mui/material';
import { styled } from '@mui/material/styles';

const StyledPaper = styled(Paper)(({ theme }) => ({
  padding: theme.spacing(4),
  marginTop: theme.spacing(2),
  borderRadius: '16px',
  boxShadow: '0 4px 6px rgba(0, 0, 0, 0.1)',
}));

export default function CalorieCalc() {
  const [formData, setFormData] = useState({
    age: '',
    weight: '',
    height: '',
    gender: 'male',
    activityLevel: 'sedentary',
  });

  const [result, setResult] = useState(null);

  const activityLevels = {
    sedentary: 1.2,
    light: 1.375,
    moderate: 1.55,
    active: 1.725,
    veryActive: 1.9,
  };

  const calculateCalories = () => {
    const { age, weight, height, gender, activityLevel } = formData;
    
    if (!age || !weight || !height) return;

    const activityMultiplier = activityLevels[activityLevel];
    let bmr;

    // Mifflin-St Jeor equation
    if (gender === 'male') {
      bmr = 10 * weight + 6.25 * height - 5 * age + 5;
    } else {
      bmr = 10 * weight + 6.25 * height - 5 * age - 161;
    }

    const totalDailyEnergyExpenditure = bmr * activityMultiplier;
    setResult({
      bmr: Math.round(bmr),
      tdee: Math.round(totalDailyEnergyExpenditure),
      maintenance: Math.round(totalDailyEnergyExpenditure),
      weightLoss: Math.round(totalDailyEnergyExpenditure * 0.8),
      weightGain: Math.round(totalDailyEnergyExpenditure * 1.2),
    });
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  return (
    <Box sx={{ maxWidth: 600, mx: 'auto', mt: 4 }}>
      <Typography variant="h4" component="h1" gutterBottom align="center">
        Calorie Calculator
      </Typography>

      <StyledPaper>
        <Grid container spacing={3}>
          {/* Gender */}
          <Grid item xs={12}>
            <FormControl fullWidth>
              <InputLabel>Gender</InputLabel>
              <Select
                value={formData.gender}
                onChange={handleChange}
                name="gender"
              >
                <MenuItem value="male">Male</MenuItem>
                <MenuItem value="female">Female</MenuItem>
              </Select>
            </FormControl>
          </Grid>

          {/* Age */}
          <Grid item xs={12} sm={6}>
            <TextField
              fullWidth
              label="Age"
              type="number"
              name="age"
              value={formData.age}
              onChange={handleChange}
              InputProps={{ inputProps: { min: 0 } }}
            />
          </Grid>

          {/* Weight */}
          <Grid item xs={12} sm={6}>
            <TextField
              fullWidth
              label="Weight (kg)"
              type="number"
              name="weight"
              value={formData.weight}
              onChange={handleChange}
              InputProps={{ inputProps: { min: 0 } }}
            />
          </Grid>

          {/* Height */}
          <Grid item xs={12} sm={6}>
            <TextField
              fullWidth
              label="Height (cm)"
              type="number"
              name="height"
              value={formData.height}
              onChange={handleChange}
              InputProps={{ inputProps: { min: 0 } }}
            />
          </Grid>

          {/* Activity Level */}
          <Grid item xs={12} sm={6}>
            <FormControl fullWidth>
              <InputLabel>Activity Level</InputLabel>
              <Select
                value={formData.activityLevel}
                onChange={handleChange}
                name="activityLevel"
              >
                <MenuItem value="sedentary">Sedentary (little or no exercise)</MenuItem>
                <MenuItem value="light">Lightly active (light exercise/sports 1-3 days/week)</MenuItem>
                <MenuItem value="moderate">Moderately active (moderate exercise/sports 3-5 days/week)</MenuItem>
                <MenuItem value="active">Very active (hard exercise/sports 6-7 days a week)</MenuItem>
                <MenuItem value="veryActive">Super active (very hard exercise/physical job)</MenuItem>
              </Select>
            </FormControl>
          </Grid>

          {/* Calculate Button */}
          <Grid item xs={12}>
            <Button
              variant="contained"
              color="primary"
              fullWidth
              onClick={calculateCalories}
              disabled={!formData.age || !formData.weight || !formData.height}
            >
              Calculate
            </Button>
          </Grid>

          {/* Results */}
          {result && (
            <Grid item xs={12}>
              <Paper sx={{ p: 3, mt: 3, borderRadius: '12px' }}>
                <Typography variant="h6" gutterBottom>
                  Your Results
                </Typography>
                <Typography variant="body1">
                  Basal Metabolic Rate (BMR): {result.bmr} calories/day
                </Typography>
                <Typography variant="body1">
                  Total Daily Energy Expenditure (TDEE): {result.tdee} calories/day
                </Typography>
                <Typography variant="body1">
                  Maintenance: {result.maintenance} calories/day
                </Typography>
                <Typography variant="body1">
                  Weight Loss: {result.weightLoss} calories/day (1 lb/week)
                </Typography>
                <Typography variant="body1">
                  Weight Gain: {result.weightGain} calories/day (1 lb/week)
                </Typography>
              </Paper>
            </Grid>
          )}
        </Grid>
      </StyledPaper>
    </Box>
  );
}
